// src/LetterBox.js
import React from "react";

class LetterBox extends React.Component {
  static defaultProps = {
    letter: "",
    isVisible: true,
    wrong: false,
    boxStyle: {},
    className: "",
    blankChar: "_",
  };

  render() {
    const { letter, isVisible, wrong, boxStyle, className, blankChar } =
      this.props;

    const content = isVisible
      ? String(letter || "").slice(0, 1).toUpperCase()
      : String(blankChar || "_");

    const baseStyle = {
      display: "inline-flex",
      alignItems: "center",
      justifyContent: "center",
      padding: "4px 10px",            // a touch more padding
      margin: "3px",
      minWidth: 28,                    // slightly wider
      height: 32,                      // slightly taller
      border: "1.5px solid #e2e2e2",   // a hair thicker
      borderRadius: 10,                // a bit rounder
      fontWeight: 700,
      fontSize: 16,                    // a bit larger text
      letterSpacing: "0.03em",
      textTransform: "uppercase",
      background: wrong ? "#fff0f0" : "#ffffff",
      color: wrong ? "#b33" : "#222",
      boxShadow: "0 1px 0 rgba(0,0,0,0.05)",  // subtle depth
      transition: "transform .06s ease, box-shadow .15s ease",
      userSelect: "none",
      ...boxStyle,
    };

    const classes = `letter ${wrong ? "wrong" : ""} ${className}`.trim();

    return (
      <span
        className={classes}
        style={baseStyle}
        aria-label={`letter-${content}`}
      >
        {content}
      </span>
    );
  }
}

export default LetterBox;
